import { ref } from 'vue';

const DEFAULTS = {
  '数值': { '饱食度': 70, '精神值': 80, '心情值': 60, '性欲值': 10, '快感值': 0, '整体色情值': 25 },
  '主角': { '金钱': 1800 },
  '衣柜': {
    '当前穿着': ['居家蕾丝睡裙'],
    '可选服装': {
      '居家蕾丝睡裙': { '部位标签': ['外套'], '风格标签': ['居家'], '颜色标签': ['白色'], '材质标签': ['蕾丝'], '色情值': 60 },
      '休闲纯棉T恤': { '部位标签': ['内衬'], '风格标签': ['日常', '休闲'], '颜色标签': ['白色'], '材质标签': ['纯棉'], '色情值': 25 },
      '休闲运动短裙': { '部位标签': ['下装'], '风格标签': ['日常', '休闲', '运动'], '颜色标签': ['黑色'], '材质标签': ['涤纶'], '色情值': 50 },
      '休闲帆布鞋': { '部位标签': ['鞋'], '风格标签': ['日常', '休闲'], '颜色标签': ['白色'], '材质标签': ['帆布'], '色情值': 5 },
      '休闲卫裤': { '部位标签': ['下装'], '风格标签': ['日常', '休闲', '运动'], '颜色标签': ['灰色'], '材质标签': ['纯棉'], '色情值': 15 },
      '休闲连帽卫衣': { '部位标签': ['外套'], '风格标签': ['日常', '休闲', '运动'], '颜色标签': ['灰色'], '材质标签': ['纯棉抓绒'], '色情值': 10 },
      '日常紧身牛仔裤': { '部位标签': ['下装'], '风格标签': ['日常', '休闲'], '颜色标签': ['蓝色'], '材质标签': ['牛仔'], '色情值': 40 },
      '日常棉质内衣': { '部位标签': ['内衣'], '风格标签': ['日常'], '颜色标签': ['肉色'], '材质标签': ['棉质混纺'], '色情值': 35 },
      '日常纯棉内衣': { '部位标签': ['内衣'], '风格标签': ['日常'], '颜色标签': ['白色'], '材质标签': ['棉质'], '色情值': 30 },
      '休闲棉袜': { '部位标签': ['腿部'], '风格标签': ['日常', '休闲'], '颜色标签': ['白色'], '材质标签': ['棉质'], '色情值': 30 },
    },
  },
  '日程': { '日期': '2024-09-01', '星期': '周日', '当前任务': { '任务名': '无' }, '可用任务': [] },
  '社交': { '联系人': {} },
};

function getData() {
  const r = { ...DEFAULTS };
  // 从 stat_data 读取
  try {
    const th = (window.parent as any).TavernHelper;
    const v = th?.getVariables?.({ type: 'message' });
    const sd = v?.stat_data || v?.display_data;
    if (sd && typeof sd === 'object' && Object.keys(sd).length > 0) {
      for (const k of Object.keys(sd)) {
        if (sd[k] !== null && typeof sd[k] === 'object' && !Array.isArray(sd[k])) {
          r[k] = { ...(r[k] || {}), ...sd[k] };
        } else {
          r[k] = sd[k];
        }
      }
    }
  } catch (e) {}
  // 从最新AI回复JSONPatch解析
  try {
    const st = (window.parent as any).SillyTavern || (window as any).SillyTavern;
    const ctx = st?.getContext?.();
    if (ctx?.chat) {
      for (let i = ctx.chat.length - 1; i >= 0; i--) {
        const msg = ctx.chat[i];
        if (msg?.is_user) continue;
        const text = msg?.mes || '';
        const tail = text.substring(Math.max(0, text.length - 2000));
        const uvMatch = tail.match(/<UpdateVariable>([\s\S]*?)<\/UpdateVariable>/);
        if (!uvMatch) continue;
        const jpMatch = uvMatch[1].match(/<JSONPatch>([\s\S]*?)<\/JSONPatch>/);
        if (!jpMatch) continue;
        try {
          const patches = JSON.parse(jpMatch[1]);
          for (const p of patches) {
            if (p.path === '/衣柜/当前穿着' && Array.isArray(p.value)) {
              r['衣柜'] = r['衣柜'] || {};
              r['衣柜']['当前穿着'] = p.value;
            }
            if (p.path === '/日程/当前任务' && p.value?.['任务名']) {
              r['日程'] = r['日程'] || {};
              r['日程']['当前任务'] = p.value;
            }
            if (p.path === '/日程/可用任务' && Array.isArray(p.value)) {
              r['日程'] = r['日程'] || {};
              r['日程']['可用任务'] = p.value;
            }
            if (p.path === '/主角/金钱') {
              r['主角'] = r['主角'] || {};
              r['主角']['金钱'] = Number(p.value);
            }
            if (p.path === '/数值/整体色情值') {
              r['数值'] = r['数值'] || {};
              r['数值']['整体色情值'] = Number(p.value);
            }
            if (p.path === '/数值/饱食度') {
              r['数值'] = r['数值'] || {};
              r['数值']['饱食度'] = Number(p.value);
            }
            if (p.path === '/数值/精神值') {
              r['数值'] = r['数值'] || {};
              r['数值']['精神值'] = Number(p.value);
            }
          }
        } catch (e) {}
        break;
      }
    }
  } catch (e) {}
  return r;
}

const _data = ref(getData());
setInterval(() => {
  _data.value = getData();
}, 2000);

export function useDataStore() {
  return _data;
}
